                    ],
                    'Tông Thất Hoàng Gia': [ 
                        { name: 'Phụng chiếu thảo tặc', description: 'Nhận được Huyết Chiếu trong đai ngọc của hoàng đế, bí mật chiêu binh mãi mã phạt tặc.' }
                    ]
                },
                lilithModes: [ 
                    { name:'Chế độ "Điêu Thuyền" (Bế Nguyệt - Quyến rũ, khéo léo, lả lướt)', cost:0 },
                    { name:'Chế độ "Tây Thi" (Trầm Ngư - Mềm mỏng, nhẫn nhục, thông minh)', cost:10 }, 
                    { name:'Chế độ "Vương Chiêu Quân" (Lạc Nhạn - Cương nghị, tài hoa, u buồn)', cost:20 },
                    { name:'Chế độ "Dương Quý Phi" (Tu Hoa - Kiêu sa, nũng nịu, lộng lẫy)', cost:30 }
                ],
                customCosts: { race: 80, identity: 60, equipment: 50, item: 30, skill: 60, redThread: 300, background: 40 } 
            };

            // Holds current runtime data
            let DATA = { ...DATA_POOL, backgrounds: [] };

            const elements = {
                reincarnationPointsDisplay:document.getElementById("reincarnationPointsDisplay"),
