    .corner-bl { bottom: 12px; left: 12px; border-right: none; border-top: none; }
    .corner-br { bottom: 12px; right: 12px; border-left: none; border-top: none; }
    .corner-art::after { content: '❖'; position: absolute; font-size: 20px; color: var(--gold-dark); }
    .corner-tl::after { top: -8px; left: -5px; } .corner-tr::after { top: -8px; right: -5px; }
    .corner-bl::after { bottom: -8px; left: -5px; } .corner-br::after { bottom: -8px; right: -5px; }

    /* --- [ Header ] --- */
