    }
    .rune-btn:hover .rune-tooltip, .rune-btn.active .rune-tooltip { opacity: 1; bottom: -28px; }

    /* --- [ Sân Khấu Chính ] --- */
    .stage-container { flex-grow: 1; padding: 20px 30px; overflow-y: auto; position: relative; z-index: 5; }
    .fade-effect { animation: pageReveal 0.5s ease-out forwards; }
