    h2.art-title::after { content: '— ❧ —'; display: block; font-size: 0.4em; color: var(--gold-dark); font-family: var(--font-body); margin-top: 5px; }

    /* Thanh tinh thể */
    .crystal-bar-row { display: flex; align-items: center; gap: 10px; margin-bottom: 8px; }
