    .page-btn:hover:not(:disabled) { background: var(--gold-dark); color: #fff; }

    /* =========================================
       [ Gói Nâng Cấp Hình Ảnh: Đường Nét Huyền Bí ]
       ========================================= */
    #grimoire-container { border: 3px solid var(--ink-primary); outline: 4px double var(--gold-dark); outline-offset: -10px; }
    h2.art-title { position: relative; display: flex; align-items: center; justify-content: center; gap: 15px; color: var(--ink-primary); text-shadow: 1px 1px 0 rgba(212, 175, 55, 0.3); }
    h2.art-title::before, h2.art-title::after { content: ""; flex: 1; height: 2px; background: linear-gradient(90deg, transparent, var(--gold-dark), transparent); max-width: 100px; position: relative; top: 2px; }
