    .corner-art {
        border: none; width: 60px; height: 60px;
        background-image: url("data:image/svg+xml,%3Csvg width='60' height='60' viewBox='0 0 60 60' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M2,2 L2,20 M2,2 L20,2' stroke='%238A6E25' stroke-width='3' fill='none'/%3E%3Cpath d='M5,5 L5,15 M5,5 L15,5' stroke='%232B221E' stroke-width='1' fill='none'/%3E%3Ccircle cx='5' cy='5' r='2' fill='%238A6E25'/%3E%3C/svg%3E");
        background-repeat: no-repeat; opacity: 0.8;
    }
    .corner-tr { transform: rotate(90deg); }
    .corner-br { transform: rotate(180deg); }
    .corner-bl { transform: rotate(270deg); }
    .corner-art::after { display: none; }

    /* =========================================
       [ Gói Tinh Chỉnh Đường Nét Thanh Lịch ]
       ========================================= */
    .corner-art {
        border: none; width: 50px; height: 50px; opacity: 0.7; background-size: contain; background-repeat: no-repeat;
        background-image: url("data:image/svg+xml,%3Csvg width='50' height='50' viewBox='0 0 50 50' xmlns='http://www.w3.org/2000/svg'%3E%3Cpath d='M2,50 L2,15 Q2,2 15,2 L50,2' fill='none' stroke='%238A6E25' stroke-width='2'/%3E%3Cpath d='M5,50 L5,20 Q5,5 20,5 L50,5' fill='none' stroke='%23594A42' stroke-width='1'/%3E%3Ccircle cx='5' cy='5' r='2' fill='%238A6E25'/%3E%3Cpath d='M15,15 L25,5' stroke='%238A6E25' stroke-width='1'/%3E%3C/svg%3E");
    }
    .corner-tr { transform: scaleX(-1); }
    .corner-bl { transform: scaleY(-1); }
    .corner-br { transform: scale(-1); }
    .corner-art::after { display: none; }

    h2.art-title { margin-bottom: 30px; position: relative; }
    h2.art-title::after {
        content: ""; display: block; width: 60%; height: 15px; margin: 5px auto 0 auto;
        background-image: url("data:image/svg+xml,%3Csvg width='200' height='10' viewBox='0 0 200 10' xmlns='http://www.w3.org/2000/svg'%3E%3Cline x1='0' y1='5' x2='200' y2='5' stroke='%238A6E25' stroke-width='1' stroke-dasharray='190, 10'/%3E%3Crect x='95' y='0' width='10' height='10' transform='rotate(45 100 5)' fill='%238A6E25'/%3E%3C/svg%3E");
        background-repeat: no-repeat; background-position: center; opacity: 0.6;
    }

    .fancy-line, .art-divider { height: 20px; border: none; background: none; position: relative; opacity: 0.5; }
    .fancy-line::before, .fancy-line::after, .art-divider::before, .art-divider::after { display: none; }
    .fancy-line {
        background-image: url("data:image/svg+xml,%3Csvg width='100%25' height='10' preserveAspectRatio='none' viewBox='0 0 200 10' xmlns='http://www.w3.org/2000/svg'%3E%3Cline x1='0' y1='5' x2='200' y2='5' stroke='%23594A42' stroke-width='1' stroke-opacity='0.5'/%3E%3Ccircle cx='100' cy='5' r='3' fill='%238A6E25'/%3E%3Ccircle cx='90' cy='5' r='1' fill='%23594A42'/%3E%3Ccircle cx='110' cy='5' r='1' fill='%23594A42'/%3E%3C/svg%3E");
        background-position: center; background-repeat: no-repeat;
    }

    details.art-card { box-shadow: inset 0 0 0 1px rgba(138, 110, 37, 0.15); }
    .magic-btn { border: 1px double var(--gold-dark); font-weight: bold; }
    .detail-item { border-bottom: 1px dashed rgba(138, 110, 37, 0.2); }
    </style>
</head>
<body>

    <div id="grimoire-container">
        <div class="corner-art corner-tl"></div><div class="corner-art corner-tr"></div>
        <div class="corner-art corner-bl"></div><div class="corner-art corner-br"></div>

        <div class="astral-header">
            <div class="header-data"><i class="fa-solid fa-hourglass-half header-divider"></i> <span id="val-time">--:--</span></div>
            <div class="header-divider">✦</div>
            <div class="header-data"><i class="fa-solid fa-compass header-divider"></i> <span id="val-location">Vùng Hư Vô</span></div>
            <div class="header-divider">✦</div>
            <div class="header-data"><i class="fa-solid fa-cloud-moon header-divider"></i> <span id="val-weather">--</span></div>
            <div class="header-divider">✦</div>
            <div class="header-data"><i class="fa-solid fa-crown header-divider"></i> Uy Danh: <span id="val-rep">0</span></div>
        </div>

        <div class="rune-nav" id="nav-bar">
            <div class="rune-btn active" onclick="window.UI.switch('hero', this)"><i class="fa-solid fa-chess-king"></i><div class="rune-tooltip">Nhân Vật</div></div>
            <div class="rune-btn" onclick="window.UI.switch('map', this)"><i class="fa-solid fa-map-location-dot"></i><div class="rune-tooltip">Bản Đồ</div></div>
            <div class="rune-btn" onclick="window.UI.switch('contacts', this)"><i class="fa-solid fa-users"></i><div class="rune-tooltip">Mối Quan Hệ</div></div>
            <div class="rune-btn" style="border-color:var(--accent-red); color:var(--accent-red);" onclick="window.UI.switch('destiny', this)"><i class="fa-solid fa-heart-pulse"></i><div class="rune-tooltip" style="color:var(--accent-red)">Tơ Hồng</div></div>
            <div class="rune-btn" onclick="window.UI.switch('quests', this)"><i class="fa-solid fa-scroll"></i><div class="rune-tooltip">Nhiệm Vụ</div></div>
            <div class="rune-btn" onclick="window.UI.switch('bag', this)"><i class="fa-solid fa-gem"></i><div class="rune-tooltip">Hành Trang</div></div>
            <div class="rune-btn" onclick="window.UI.switch('codex', this)"><i class="fa-solid fa-book-atlas"></i><div class="rune-tooltip">Từ Điển</div></div>
            <div class="rune-btn" onclick="window.UI.switch('news', this)"><i class="fa-solid fa-newspaper"></i><div class="rune-tooltip">Tin Tức</div></div>
        </div>

        <div id="stage" class="stage-container"></div>

        <div id="battle-ui" class="hidden">
            <h2 class="art-title" style="color:var(--accent-red); margin-bottom:10px;">⚔ Quyết Đấu Định Mệnh ⚔</h2>
            <div class="battle-teams">
                <div class="battle-team-box" id="team-ally">
                    <div class="battle-header">Đồng Minh Ánh Sáng</div>
                    <div id="ally-list"></div>
                </div>
                <div class="battle-team-box" id="team-enemy" style="border-color:var(--accent-red)">
                    <div class="battle-header" style="color:var(--accent-red)">Quái Vật Vực Thẳm</div>
                    <div id="enemy-list"></div>
                </div>
            </div>
            <div class="battle-controls">
                <div class="skill-panel">
                    <div style="display:flex; gap:10px; margin-bottom:10px; border-bottom:1px solid #444; padding-bottom:5px;">
                        <span class="tab-btn active" onclick="window.Battle.switchTab('skills')" id="btn-b-skill">Kỹ Năng</span>
                        <span class="tab-btn" onclick="window.Battle.switchTab('items')" id="btn-b-item">Vật Phẩm</span>
                    </div>
                    <div id="battle-actions-list"></div>
                </div>
                <div class="core-actions">
                    <button class="ritual-btn" onclick="window.Battle.sendAction('Tấn Công')">Tấn Công</button>
                    <button class="ritual-btn" style="border-color:var(--gold-dark); color:var(--gold-dark);" onclick="window.Battle.sendAction('Phòng Thủ')">Phòng Thủ</button>
                    <button class="ritual-btn" style="border-color:#555; color:#aaa; font-size:1em;" onclick="window.Battle.sendAction('Rút Lui')">Rút Lui</button>
                </div>
            </div>
            <div class="log-area" id="battle-log"></div>
            <div style="display:flex; gap:10px;">
                <input type="text" id="battle-input" placeholder="Nhập hành động tùy chỉnh..." style="flex-grow:1; background:#222; border:1px solid #444; color:#fff; padding:5px;">
                <button class="magic-btn" onclick="window.Battle.submitInput()" style="color:#fff; border-color:#fff;">Thực Thi</button>
                <button id="end-battle-btn" class="magic-btn hidden" onclick="window.UI.send('/send [Kết Thúc Chiến Đấu] |/trigger')" style="background:var(--accent-gold); color:#000;">Khải Hoàn</button>
            </div>
        </div>
    </div>

<script>
    (function() {
        if (window.ROYAL_GRIMOIRE_V19_FINAL) return;
        window.ROYAL_GRIMOIRE_V19_FINAL = true;
        console.log("--- [Hư Không Vận Mệnh V19 Remake - Việt Hóa (Fixed)] Khởi tạo ---");

        // --- [ 1. Công Cụ Dữ Liệu ] ---
        const isObject = (item) => (item && typeof item === 'object' && !Array.isArray(item));

        const deepMerge = (target, source) => {
            let output = Object.assign({}, target);
            if (isObject(target) && isObject(source)) {
                Object.keys(source).forEach(key => {
                    if (key === '$meta' || key === '//reason') return;
                    if (isObject(source[key])) {
                        if (!(key in target)) Object.assign(output, { [key]: source[key] });
                        else output[key] = deepMerge(target[key], source[key]);
                    } else { Object.assign(output, { [key]: source[key] }); }
                });
            }
            return output;
        };
        const SafeGet = (obj, path, def) => {
            try {
                let curr = obj;
                for (let key of path.split('.')) {
                    if (!curr || typeof curr !== 'object') return def;
                    let match = key.match(/^(.+?)\[(\d+)\]$/);
                    if (match) {
                        if (Array.isArray(curr[match[1]])) curr = curr[match[1]][parseInt(match[2])];
                        else return def;
                    } else { curr = curr[key]; }
                }
                return curr === undefined ? def : curr;
            } catch (e) { return def; }
        };
        const cleanKeys = (obj) => {
            if (!obj || typeof obj !== 'object') return [];
            return Object.keys(obj).filter(k => k !== '$meta' && k !== '//reason');
        };
        // --- [ 2. Quản Lý Trạng Thái ] ---
        let currentData = {};
        let activeTab = 'hero';
        let heroSubTab = 'core'; 
        let battleTarget = null;
        let battleTab = 'skills';
        window.invFilter = 'Tất Cả';
        // --- [ Mới: Quản Lý Phân Trang Toàn Cục ] ---
        const ITEMS_PER_PAGE = 8;
        // Ghi lại trang hiện tại của từng module
        let pageState = {
            bag: 1,
            contacts: 1, // Mối Quan Hệ
            destiny: 1,  // Tơ Hồng
            skills: 1,   // Kỹ Năng
            codex: 1     // Từ Điển
        };
        // --- [ Hỗ Trợ: HTML Phân Trang ] ---
        function renderPaginationHtml(moduleName, totalPages) {
            // Chỉ hiển thị khi có nhiều hơn 1 trang
            if (totalPages <= 1) return '';
            const cur = pageState[moduleName] || 1;

            // Sửa lỗi vượt trang
            if(cur > totalPages) pageState[moduleName] = totalPages;
            return `
            <div class="pagination-ctrl">
                <button class="page-btn" ${cur <= 1 ? 'disabled' : ''} onclick="window.UI.changePage('${moduleName}', -1)">
                    <i class="fa-solid fa-angle-left"></i> Quyển Trước
                </button>
                <span style="font-size:0.9em; font-weight:bold; color:var(--ink-primary);">Quyển ${cur} / ${totalPages}</span>
                <button class="page-btn" ${cur >= totalPages ? 'disabled' : ''} onclick="window.UI.changePage('${moduleName}', 1)">
                    Quyển Sau <i class="fa-solid fa-angle-right"></i>
                </button>
            </div>`;
        }
     // --- [ 3. Trung Tâm Điều Khiển (Bản Sửa Lỗi) ] ---
        window.UI = {
            // Chuyển tab lớn
            switch: (tab, el) => {
                activeTab = tab;
                // Reset về trang 1 khi chuyển tab
                if (pageState[tab]) pageState[tab] = 1;
                document.querySelectorAll('.rune-nav .rune-btn').forEach(b => b.classList.remove('active'));
                if(el) el.classList.add('active');
                renderStage();
            },

            // Chuyển tab con nhân vật
            switchHeroTab: (tab) => { 
                heroSubTab = tab;
                pageState.skills = 1; // Reset trang kỹ năng
                renderStage();
            },

            // Lọc túi đồ
            switchInvFilter: (filter) => { 
                window.invFilter = filter;
                pageState.bag = 1;
                renderStage(); 
            },

            // Điều khiển chuyển trang chung
            changePage: (type, offset) => {
                if (!pageState[type]) pageState[type] = 1;
                pageState[type] += offset;

                if (pageState[type] < 1) pageState[type] = 1;
                renderStage();
                // Cuộn lên đầu
                const stage = document.getElementById('stage');
                if (stage) stage.scrollTop = 0;
            },

            // Gửi lệnh
            send: (cmd) => {
                if(typeof triggerSlash === 'function') triggerSlash(cmd);
                else if (typeof send === 'function') send(cmd);
                else console.log(`Gửi lệnh giả lập: ${cmd}`);
            }
        };

        function renderAll() {
            // [ĐỒNG BỘ BIẾN] Trạng Thái UI
            const uiMode = SafeGet(currentData, 'TrạngTháiUI.GiaoDiệnHiệnTại[0]', 'ThườngNgày');
            const isBattle = uiMode === 'ChiếnĐấu';

            document.getElementById('nav-bar').classList.toggle('hidden', isBattle);
            document.getElementById('stage').classList.toggle('hidden', isBattle);
            document.getElementById('battle-ui').classList.toggle('hidden', !isBattle);

            renderHeader();
            if(isBattle) window.Battle.render();
            else renderStage();
        }

        function renderHeader() {
            // [ĐỒNG BỘ BIẾN] Thế Giới
            const w = SafeGet(currentData, 'ThếGiới', {});
            document.getElementById('val-time').innerText = SafeGet(w, 'ThờiGian[0]', '??:??');
            document.getElementById('val-location').innerText = SafeGet(w, 'ĐịaĐiểm[0]', 'Mê Vụ');
            document.getElementById('val-weather').innerText = SafeGet(w, 'ThờiTiết[0]', 'Không');
            document.getElementById('val-rep').innerText = SafeGet(w, 'DanhTiếngHiệnTại[0]', '0');
        }

        function renderStage() {
            const stage = document.getElementById('stage');
            stage.innerHTML = '';
            stage.classList.remove('fade-effect');
            void stage.offsetWidth; 
            stage.classList.add('fade-effect');

            let html = '';
            switch(activeTab) {
                case 'hero': html = renderHero();
                break;
                case 'map': html = renderMap(); break;
                case 'contacts': html = renderContacts(false); break;
                case 'destiny': html = renderDestiny(); break;
                case 'quests': html = renderQuests(); break;
                case 'bag': html = renderBag(); break;
                case 'codex': html = renderCodex(); break;
                case 'news': html = renderNews(); break;
            }
            stage.innerHTML = html;
        }

        // --- [ 4. Logic Các Phần ] ---

        // [Việt Hóa & Đồng Bộ] Render Bản Đồ
        function renderMap() {
            // [ĐỒNG BỘ BIẾN] Thế Giới -> Địa Điểm Lân Cận
            const rawLocs = SafeGet(currentData, 'ThếGiới.ĐịaĐiểmLânCận[0]', []);
            let locs = [];
            if (Array.isArray(rawLocs)) {
                locs = rawLocs.map(l => {
                    if (typeof l === 'string') return { name: l, desc: 'Khu vực chưa biết...' };
                    if (Array.isArray(l) && l.length > 0) return { name: l[0], desc: l[1] || 'Dường như không có gì đặc biệt.' };
                    return null;
                }).filter(l => l && l.name && l.name !== 'Chưa rõ');
            }

            const getIcon = (name) => {
                if (name.includes('Rừng') || name.includes('Cây')) return 'fa-tree';
                if (name.includes('Thành') || name.includes('Trấn') || name.includes('Thôn') || name.includes('Làng')) return 'fa-city';
                if (name.includes('Biển') || name.includes('Sông') || name.includes('Nước') || name.includes('Hồ')) return 'fa-water';
                if (name.includes('Núi') || name.includes('Vực')) return 'fa-mountain';
                if (name.includes('Tháp') || name.includes('Di Tích') || name.includes('Động')) return 'fa-dungeon';
                return 'fa-map-pin';
            };
            const listHtml = locs.map(l => `
                <div class="location-card">
                    <div style="display:flex; align-items:center; flex-grow:1;">
                        <div class="loc-icon-area">
                            <i class="fa-solid ${getIcon(l.name)}"></i>
                            <i class="fa-solid fa-caret-down" style="font-size:0.5em; opacity:0.5;"></i>
                        </div>
                        <div class="loc-info">
                            <div class="loc-name">${l.name}</div>
                            <div class="loc-desc">${l.desc}</div>
                        </div>
                    </div>
                    <button class="stamp-btn" onclick="window.UI.send('/send Đi đến ${l.name} |/trigger')">
                        <i class="fa-solid fa-shoe-prints"></i> Lên Đường
                    </button>
                </div>
            `).join('');
            return `
            <h2 class="art-title">Thám Hiểm Vùng Đất</h2>
            <div style="display:flex; justify-content:space-between; align-items:flex-end; margin-bottom:20px; padding:0 10px;">
                <span style="font-family:var(--font-header); color:var(--ink-secondary); font-size:0.9em;">
                    <i class="fa-solid fa-compass"></i> Kết quả trinh sát hiện tại
                </span>
                <button class="magic-btn" onclick="window.UI.send('/send Khám phá xung quanh |/trigger')">
                    <i class="fa-solid fa-arrows-rotate"></i> Vẽ Lại Bản Đồ
                </button>
            </div>
            <div style="padding:5px;">
                ${listHtml || '<div style="text-align:center; padding:40px; font-style:italic; opacity:0.6; border:2px dashed #ccc;">Sương mù quá dày, không thể nhìn rõ đường đi...</div>'}
            </div>`;
        }

        // Render Thẻ Nhân Vật (Dùng chung cho Mối Quan Hệ và Tơ Hồng)
        function renderCharacterCard(c, k, isRedLine) {
            // --- [ 1. Trích Xuất Thông Tin Cơ Bản (ĐỒNG BỘ BIẾN) ] ---
            const name = SafeGet(c, 'Tên[0]', k);
            const race = SafeGet(c, 'ChủngTộc[0]', 'Chưa rõ');
            const job = SafeGet(c, 'NghềNghiệp[0]', 'Lãng Khách');
            const age = SafeGet(c, 'Tuổi[0]', '??');
            // Tuổi có thể không có trong template NPC script nhưng có trong InitVar
            const level = SafeGet(c, 'CấpĐộ[0]', '1');
            const identity = SafeGet(c, 'ThânPhận[0]', 'Thường Dân');

            // --- [ 2. Logic Hảo Cảm (Nâng Cao) ] ---
            const favorRaw = String(SafeGet(c, 'HảoCảm[0]', '0/1000'));
            // Định dạng "80" hoặc "80/1000"
            let parts = favorRaw.split('/');
            let curFavor = parseInt(parts[0]) || 0;
            let maxFavor = parseInt(parts[1]) || 1000;
            // Xử lý số âm
            const isNegative = curFavor < 0;
            // Tính độ rộng thanh (tỷ lệ tuyệt đối)
            let absMax = Math.abs(maxFavor) === 0 ? 1000 : Math.abs(maxFavor);
            let widthPercent = Math.min(100, (Math.abs(curFavor) / absMax) * 100);
            // Hiển thị [80/1000] hoặc [-80/-1000]
            const displayMax = isNegative ? `-${absMax}` : absMax;
            const favorText = `[${curFavor}/${displayMax}]`;

            // Class giao diện
            let cardModeClass = '';
            if (isRedLine) cardModeClass = 'destiny-mode';
            else if (isNegative) cardModeClass = 'negative-mode';
            // --- [ 3. Lưới Thuộc Tính (ĐỒNG BỘ BIẾN) ] ---
            const gridProps = [
                { l: 'Thân Phận', v: identity },
                { l: 'Chiến Lực', v: SafeGet(c, 'CấpĐộChiếnLực[0]') },
                { l: 'Tính Cách', v: SafeGet(c, 'TínhCách[0]') },
                { l: 'Trang Phục', v: SafeGet(c, 'TrangPhục[0]') },
                { l: 'Trang Bị', v: SafeGet(c, 'TrangBị[0]') }, 
                { l: 'Sở Thích', v: SafeGet(c, 'SởThích[0]') },
                { l: 'Ngoại Hình', v: SafeGet(c, 'NgoạiHình[0]') },
                { l: 'Đánh Giá', v: SafeGet(c, 'ĐánhGiá[0]') }
            ].filter(i => i.v && i.v !== 'Chưa rõ' && i.v !== '');
            // --- [ 4. Dữ Liệu Riêng Tư (ĐỒNG BỘ BIẾN) ] ---
            // Phần này dựa trên InitVar "ThốngKêTìnhDục" nhưng áp dụng cho NPC
            const thoughts = SafeGet(c, 'SuyNghĩNộiTâm[0]', SafeGet(c, 'SuyNghĩ[0]', ''));
            // Fallback: SuyNghĩNộiTâm (MVU AI) hoặc SuyNghĩ (cũ)

            // Cấu hình bộ phận cơ thể (Giữ nguyên hoặc Việt hóa từ khóa nếu Script AI trả về tiếng Việt)
            // Giả định AI trả về tiếng Việt như "Ngực", "Vùng kín"... nếu không sẽ cần map lại.
            // Ở đây ta dùng key tiếng Việt trực tiếp
            // [FIX ĐỒNG BỘ MVU AI] Key bộ phận cơ thể theo chuẩn MVU
            const bodyPartConfig = [
                { key: 'Vú', altKey: 'Ngực', icon: 'fa-regular fa-circle', label: 'Ngực' },
                { key: 'Lồn', altKey: 'ÂmHộ', icon: 'fa-solid fa-spa', label: 'Tư Mật' },
                { key: 'LỗĐít', altKey: 'HậuMôn', icon: 'fa-regular fa-circle-dot', label: 'Hậu Đình' },
                { key: 'DươngVật', altKey: null, icon: 'fa-solid fa-arrow-up', label: 'Dương Vật' },
                { key: 'ChânNgọc', altKey: 'Chân', icon: 'fa-solid fa-shoe-prints', label: 'Chân Ngọc' }
            ];
            const validBodyParts = bodyPartConfig.map(part => {
                // [FIX] Thử key chính (MVU AI) trước, fallback sang altKey
                let val = SafeGet(c, part.key + '[0]');
                if (!val && part.altKey) val = SafeGet(c, part.altKey + '[0]');
                return (val && val !== 'Chưa rõ') ? { ...part, val } : null;
            }).filter(Boolean);
            // Thống kê tình dục
            // [FIX ĐỒNG BỘ MVU AI] Thống kê tình dục với fallback đầy đủ
            const sex = {
                virgin: SafeGet(c, 'LàTrinhNữ[0]', SafeGet(c, 'LàTraiTân[0]', SafeGet(c, 'LàXửNữ[0]'))), // MVU AI: LàTrinhNữ, InitVar: LàTraiTân
                count: SafeGet(c, 'SốLầnGiaoHợp[0]'),
                exp: SafeGet(c, 'KinhNghiệmTìnhDục[0]', SafeGet(c, 'KinhNghiệm[0]')), // MVU AI: KinhNghiệmTìnhDục
                fetish: SafeGet(c, 'SởThíchKỳQuặc', [])
            };

            let fetishes = [];
            if(Array.isArray(sex.fetish)) {
                fetishes = Array.isArray(sex.fetish[0]) ? sex.fetish[0] : sex.fetish;
            } else if (typeof sex.fetish === 'string') {
                fetishes = [sex.fetish];
            }

            const hasPrivacy = validBodyParts.length > 0 || fetishes.length > 0 || sex.count || (sex.exp && sex.exp !== 'Chưa rõ');
            // --- [ 5. Dữ Liệu Ký Ức (ĐỒNG BỘ BIẾN) ] ---
            let memories = SafeGet(c, 'HànhLangKýỨc', null);
            // Khớp Script 1 line 22
            const memKeys = cleanKeys(memories);
            // --- [ 6. Lắp Ráp HTML ] ---
            return `
            <details class="art-card ${cardModeClass}">
                <summary class="card-header-area">
                    <div style="display:flex; flex-direction:column; gap:2px;">
                        <div class="card-name-box">
                            <i class="fa-regular ${isRedLine ? 'fa-heart' : 'fa-user'}" style="margin-right:8px; font-size:0.9em;"></i> ${name}
                            <span style="margin-left:8px; font-size:0.7em; font-weight:normal; opacity:0.6; font-family:var(--font-body);">Lv.${level}</span>
                        </div>
                        <div style="font-size:0.8em; color:var(--ink-secondary); padding-left:24px;">
                            ${race} • ${job} • ${age === '??' ? '??' : age + ' tuổi'}
                        </div>
                    </div>
                    <div style="display:flex; align-items:center; gap:10px;">
                         <div style="text-align:right; font-size:0.8em;">
                            <span style="font-weight:bold; color:${isRedLine?'var(--accent-red)':'var(--ink-primary)'}">${curFavor}</span>
                        </div>
                        <span class="fold-indicator"><i class="fa-solid fa-angle-down"></i></span>
                    </div>
                </summary>

                <div class="card-body-area">
                    <div class="favor-progress-container">
                        <div class="favor-bar-fill" style="width: ${widthPercent}%;"></div>
                        <div class="favor-text-overlay">${favorText}</div>
                    </div>

                    <div class="detail-grid" style="margin-top:15px;">
                        ${gridProps.map(p => `
                            <div class="detail-item">
                                <span class="detail-label">${p.l}</span> 
                                <span class="detail-val">${p.v}</span>
                            </div>
                        `).join('')}
                    </div>

                    ${thoughts && thoughts !== 'Chưa rõ' ? `
                        <div class="inner-thought" style="margin-top:12px;">
                            <i class="fa-solid fa-quote-left" style="opacity:0.3; margin-right:5px;"></i> ${thoughts}
                        </div>
                    ` : ''}

                    <div class="fancy-line"><span>✦</span></div>

                    ${hasPrivacy ? `
                        <details style="margin-top:5px; color:var(--ink-secondary);">
                            <summary style="cursor:pointer; font-size:0.9em; font-family:var(--font-header);">
                                <i class="fa-solid fa-user-secret" style="margin-right:5px;"></i> Hồ Sơ Mật 
                                <span style="font-size:0.8em; opacity:0.6; margin-left:5px;">(Nhấn để mở)</span>
                            </summary>

                            <div style="padding:10px; background:rgba(255,255,255,0.3); border:1px solid rgba(0,0,0,0.05); margin-top:5px; border-radius:4px;">

                                <div style="margin-bottom:10px; display:flex; gap:5px; flex-wrap:wrap;">
                                    ${sex.virgin !== undefined ? `<span class="art-badge ${sex.virgin ? 'virgin' : 'not-virgin'}">${sex.virgin ? 'Nguyên Vẹn' : 'Đã Mất'}</span>` : ''}
                                    ${sex.count ? `<span class="art-badge">Số lần H: ${sex.count}</span>` : ''}
                                    ${fetishes.map(f => `<span class="tag-pill erotic-tag">${f}</span>`).join('')}
                                </div>

                                ${sex.exp && sex.exp !== 'Chưa rõ' ? `
                                    <span class="privacy-label">Kinh Nghiệm:</span>
                                    <div class="art-text-block" style="font-style:italic;">${sex.exp}</div>
                                ` : ''}

                                ${validBodyParts.map(b => `
                                    <span class="privacy-label"><i class="${b.icon}" style="width:16px;"></i> ${b.label}:</span>
                                    <div class="art-text-block">${b.val}</div>
                                `).join('')}

                            </div>
                        </details>
                    ` : ''}

                    ${(memKeys.length > 0) ? `
                        <details style="margin-top:8px; color:var(--ink-secondary);">
                            <summary style="cursor:pointer; font-size:0.9em; font-family:var(--font-header);">
                                <i class="fa-solid fa-feather" style="margin-right:5px;"></i> Hành Lang Ký Ức (${memKeys.length})
                            </summary>
                            <div style="margin-top:8px;">
                                ${memKeys.map(mk => {
                                    const m = memories[mk];
                                    const mTitle = SafeGet(m, 'TiêuĐề[0]', mk); // Giả định key TiêuĐề
                                    const mDesc = SafeGet(m, 'MôTả[0]', '...');  // Giả định key MôTả
                                    return `
                                    <div class="memory-entry-art">
                                        <div class="mem-title">❖ ${mTitle}</div>
                                        <div class="mem-desc">${mDesc}</div>
                                    </div>`;
                                }).join('')}
                            </div>
                        </details>
                    ` : ''}

                    <div style="margin-top:12px; display:flex; justify-content:flex-end; gap:8px;">
                        <button class="magic-btn" onclick="window.UI.send('/send Gặp gỡ ${name} |/trigger')">Gặp Gỡ</button>
                        ${isRedLine ? `<button class="magic-btn" style="border-color:var(--accent-red); color:var(--accent-red);" onclick="window.UI.send('/send Hẹn hò ${name} |/trigger')">Hẹn Hò</button>` : ''}
                    </div>
                </div>
            </details>
            `;
        }

        // [Việt Hóa & Đồng Bộ] Render Danh Sách Quan Hệ
        function renderContacts() {
            // [ĐỒNG BỘ BIẾN] MốiQuanHệ
            const list = SafeGet(currentData, 'MốiQuanHệ[0]', {});
            const keys = cleanKeys(list);

            // --- Phân trang ---
            const totalPages = Math.ceil(keys.length / ITEMS_PER_PAGE);
            if (pageState.contacts > totalPages) pageState.contacts = totalPages || 1;
            const startIdx = (pageState.contacts - 1) * ITEMS_PER_PAGE;
            const pagedKeys = keys.slice(startIdx, startIdx + ITEMS_PER_PAGE);
            // ----------------

            const content = pagedKeys.length > 0 
                ? pagedKeys.map(k => renderCharacterCard(list[k], k, false)).join('') 
                : '<div style="text-align:center; opacity:0.6;">Chưa có mối quan hệ nào</div>';
            return `
                <h2 class="art-title">Nhân Mạch Lục</h2>
                <div class="fade-effect">
                    ${content}
                </div>
                ${renderPaginationHtml('contacts', totalPages)}
            `;
        }

        // [Việt Hóa & Đồng Bộ] Render Tơ Hồng
        function renderDestiny() {
            // [ĐỒNG BỘ BIẾN] HệThốngVậnMệnh -> ĐốiTượngTơHồng
            const list = SafeGet(currentData, 'HệThốngVậnMệnh.ĐốiTượngTơHồng[0]', {});
            const keys = cleanKeys(list);
            const fp = SafeGet(currentData, 'HệThốngVậnMệnh.ĐiểmVậnMệnh[0]', 0);
            // --- Phân trang ---
            const totalPages = Math.ceil(keys.length / ITEMS_PER_PAGE);
            if (pageState.destiny > totalPages) pageState.destiny = totalPages || 1;
            const startIdx = (pageState.destiny - 1) * ITEMS_PER_PAGE;
            const pagedKeys = keys.slice(startIdx, startIdx + ITEMS_PER_PAGE);
            // ----------------

            const content = pagedKeys.length > 0
                ? pagedKeys.map(k => renderCharacterCard(list[k], k, true)).join('') 
                : '<div style="text-align:center; opacity:0.6;">Chưa kết nối tơ hồng</div>';
            return `
                <h2 class="art-title" style="color:var(--accent-red)">Guồng Quay Vận Mệnh</h2>
                <div style="text-align:center; font-family:var(--font-header); font-size:1.2em; margin-bottom:20px;">
                    Điểm Vận Mệnh (FP): <span style="color:var(--gold-dark); font-weight:900;">${fp}</span>
                </div>

                <div class="fade-effect">
                    ${content}
                </div>
                ${renderPaginationHtml('destiny', totalPages)}
            `;
        }

        // [Việt Hóa & Đồng Bộ] Render Nhân Vật Chính
        function renderHero() {
            // [ĐỒNG BỘ BIẾN] NhânVậtChính
            const p = SafeGet(currentData, 'NhânVậtChính', {});
            const res = SafeGet(p, 'TàiNguyên', {});
