            const hp = SafeGet(res, 'SinhMệnh[0]', 0);
            const maxHp = SafeGet(res, 'SinhMệnhTốiĐa[0]', 100);
            const mp = SafeGet(res, 'NăngLượng[0]', 0); const maxMp = SafeGet(res, 'NăngLượngTốiĐa[0]', 100);
            const sp = SafeGet(res, 'ThểLực[0]', 0); const maxSp = SafeGet(res, 'ThểLựcTốiĐa[0]', 100);
            let navHtml = `<div class="tab-header">
