                <button class="tab-btn ${heroSubTab==='equip'?'active':''}" onclick="window.UI.switchHeroTab('equip')">Trang Bị</button>
                <button class="tab-btn ${heroSubTab==='skills'?'active':''}" onclick="window.UI.switchHeroTab('skills')">Kỹ Năng</button>
                <button class="tab-btn ${heroSubTab==='privacy'?'active':''}" onclick="window.UI.switchHeroTab('privacy')" style="color:var(--accent-purple)">Riêng Tư</button>
            </div>`;
            let contentHtml = '';

            // --- 1. Cốt Lõi ---
            if (heroSubTab === 'core') {
                const statusList = cleanKeys(SafeGet(p, 'HiệuỨngTrạngThái[0]', {})).map(k => `<div class="tag-pill">${k}</div>`).join(' ');
                contentHtml = `
                    <div class="fade-effect">
                        <h2 class="art-title" style="margin-bottom:10px;">${SafeGet(p, 'Tên[0]', 'Vô Danh')}</h2>
                        <div style="text-align:center; margin-bottom:20px; font-family:var(--font-header);">
                             <i class="fa-solid fa-certificate" style="color:var(--gold-dark);"></i> ${SafeGet(p, 'ThânPhận[0]', 'Lãng Khách')} 
                            <span style="margin:0 10px;">•</span> 
                            ${SafeGet(p, 'CấpĐộSứcMạnh[0]', 'Phàm Nhân')}
                        </div>

                        <div style="background:#fff; padding:15px; border:1px solid #ddd; box-shadow:0 2px 5px rgba(0,0,0,0.05);">
                            <div class="crystal-bar-row"><i class="fa-solid fa-heart" style="color:var(--accent-red);width:20px;"></i><div class="crystal-casing"><div class="crystal-fluid" style="width:${(hp/maxHp)*100}%; background:var(--accent-red);"></div></div><span style="font-size:0.8em;width:60px;text-align:right;">${hp}/${maxHp}</span></div>
                            <div class="crystal-bar-row"><i class="fa-solid fa-star" style="color:var(--accent-blue);width:20px;"></i><div class="crystal-casing"><div class="crystal-fluid" style="width:${(mp/maxMp)*100}%; background:var(--accent-blue);"></div></div><span style="font-size:0.8em;width:60px;text-align:right;">${mp}/${maxMp}</span></div>
                            <div class="crystal-bar-row"><i class="fa-solid fa-bolt" style="color:var(--gold-dark);width:20px;"></i><div class="crystal-casing"><div class="crystal-fluid" style="width:${(sp/maxSp)*100}%; background:var(--gold-dark);"></div></div><span style="font-size:0.8em;width:60px;text-align:right;">${sp}/${maxSp}</span></div>
                        </div>

                        <div style="margin-top:15px;">
                            <div class="detail-label">Trạng Thái:</div>
                            <div style="margin-top:5px; padding:10px; background:rgba(0,0,0,0.03); border-radius:4px; min-height:40px;">${statusList||'<span style="opacity:0.5">Bình thường</span>'}</div>
                        </div>
                    </div>`;

            // --- 2. Trang Bị ---
            } else if (heroSubTab === 'equip') {
                // [ĐỒNG BỘ BIẾN] TrangBị
                const eq = SafeGet(p, 'TrangBị[0]', {});
                const slots = [
                    { k: 'VũKhí', icon: 'fa-khanda', label: 'Vũ Khí' },
                    { k: 'Giáp', icon: 'fa-shield-halved', label: 'Giáp Trụ' },
                    { k: 'TrangSức', icon: 'fa-ring', label: 'Trang Sức' },
                    { k: 'NộiY', icon: 'fa-socks', label: 'Nội Y' }, 
                    { k: 'ĐặcBiệt', icon: 'fa-gem', label: 'Vật Phẩm Đặc Biệt' }
                ];

                contentHtml = slots.map(s => {
                    const val = SafeGet(eq, s.k+'[0]', null);
                    const displayVal = (val && val !== '(Không)') ? val : '<span style="opacity:0.4; font-weight:normal;">( Trống )</span>';
                    return `
                    <div class="equip-row">
                        <div class="equip-icon-box"><i class="fa-solid ${s.icon}"></i></div>
                        <div style="flex-grow:1;">
                            <div class="equip-label">${s.label}</div>
                            <div class="equip-val">${displayVal}</div>
                        </div>
                        ${(val && val !== '(Không)') ? '<i class="fa-solid fa-circle-check" style="color:var(--accent-green);"></i>' : ''}
                    </div>`;
                }).join('');

                contentHtml = `<h2 class="art-title">Danh Sách Trang Bị</h2><div class="fade-effect" style="background:#fff; border:1px solid #ccc; padding:10px;">${contentHtml}</div>`;
            // --- 3. Kỹ Năng ---
            } else if (heroSubTab === 'skills') {
                // [ĐỒNG BỘ BIẾN] KỹNăng
                const skills = SafeGet(p, 'KỹNăng[0]', {});
                const keys = cleanKeys(skills);

                // --- Phân trang ---
                const totalPages = Math.ceil(keys.length / ITEMS_PER_PAGE);
                if (pageState.skills > totalPages) pageState.skills = totalPages || 1;
                const startIdx = (pageState.skills - 1) * ITEMS_PER_PAGE;
                const pagedKeys = keys.slice(startIdx, startIdx + ITEMS_PER_PAGE);
                // ----------------

                if(keys.length === 0) {
                    contentHtml = `
                    <div style="text-align:center; padding:50px; opacity:0.6; border:2px dashed #ccc; margin:20px;">
                        <i class="fa-solid fa-book-dead" style="font-size:3em; margin-bottom:15px; color:var(--ink-secondary);"></i><br>
                        <span style="font-family:var(--font-header); font-size:1.2em;">Chưa lĩnh hội kỹ năng nào</span>
                    </div>`;
                } else {
                    const cardsHtml = pagedKeys.map(k => {
                        const sk = skills[k];

                        const name = SafeGet(sk, 'Tên[0]', k);
                        const lv = SafeGet(sk, 'CấpĐộ[0]', 1);
                        // FIX: Đổi 'TiêuHao' -> 'cost' (có fallback)
                        const cost = SafeGet(sk, 'cost[0]', SafeGet(sk, 'TiêuHao[0]', 'Không'));
                        const desc = SafeGet(sk, 'MôTả[0]', 'Chưa có mô tả...');

                        // [tags]
                        let tagList = SafeGet(sk, 'tags[0]', []);
                        if (!Array.isArray(tagList)) tagList = []; 

                        const tagsHtml = tagList.map(t => `<span class="skill-tag">${t}</span>`).join('');

                        return `
                        <div class="skill-art-card">
                            <div class="skill-header-row">
                                <div class="skill-name">${name}</div>
                                <div class="skill-level-badge">Lv.${lv}</div>
                            </div>

                            <div class="skill-cost">
                                <i class="fa-solid fa-bolt" style="font-size:0.9em;"></i> ${cost}
                            </div>

                            ${tagList.length > 0 ? `<div class="skill-tags-row">${tagsHtml}</div>` : ''}

                            <div class="card-desc">${desc}</div>

                            <button class="magic-btn" style="margin-top:auto; width:100%; text-align:center; padding:8px;"
                            onclick="window.UI.send('/send [Sử dụng kỹ năng] ${k} |/trigger')">
                                <i class="fa-solid fa-wand-magic-sparkles"></i> Niệm Chú
                            </button>
                        </div>`;
                    }).join('');

                    contentHtml = `<div class="skill-grid fade-effect">${cardsHtml}</div>`;
                }

                contentHtml = `
                    <h2 class="art-title">Thư Viện Kỹ Năng <span style="font-size:0.6em; opacity:0.5; vertical-align:middle;">(Tổng ${keys.length})</span></h2>
                    ${contentHtml}
                    ${renderPaginationHtml('skills', totalPages)}
                `;
            // --- 4. Riêng Tư ---
            } else if (heroSubTab === 'privacy') {
                // [ĐỒNG BỘ BIẾN] ThốngKêTìnhDục
                const sex = SafeGet(p, 'ThốngKêTìnhDục[0]', {});
                const isV = SafeGet(sex, 'LàTraiTân[0]', true);
                const fetishes = SafeGet(sex, 'SởThíchKỳQuặc', []);
                const fList = (Array.isArray(fetishes[0]) ? fetishes[0] : fetishes).map(f => `<span style="border-bottom:1px solid var(--accent-purple); margin-right:5px;">${f}</span>`).join(' ');
                contentHtml = `
                <div class="fade-effect">
                    <h2 class="art-title" style="color:var(--accent-purple)">Nhật Ký Thầm Kín</h2>
                    <div class="privacy-paper">
                        <div style="text-align:right; font-size:0.8em; opacity:0.6;">(Đốt sau khi đọc)</div>

                        <div class="privacy-section-title">Tình Trạng Cơ Thể</div>
                        <div>
                            Tôi hiện là <span style="font-weight:bold; color:${isV?'green':'var(--accent-red)'}">${isV ? 'Trai Tân/Xử Nữ' : 'Đã Mất Zin'}</span>.<br>
                            Đã trải qua mây mưa: <b>${SafeGet(sex, 'SốLầnGiaoHợp[0]', 0)}</b> lần.
                        </div>

                        <div class="privacy-section-title" style="margin-top:20px;">Sở Thích Thầm Kín</div>
                        <div>
                            ${fList || 'Chưa thức tỉnh sở thích đặc biệt nào...'}
                        </div>
                    </div>
                </div>`;
            }
            return navHtml + contentHtml;
        }

        // [Việt Hóa & Đồng Bộ] Render Hành Trang
        function renderBag() {
            // [ĐỒNG BỘ BIẾN] TàiSản -> TiềnTệ / BaLô
            const money = SafeGet(currentData, 'TàiSản.TiềnTệ', {});
            const bags = SafeGet(currentData, 'TàiSản.BaLô[0]', {});

            // 1. Tiền tệ
            const moneyHtml = `<div style="display:flex; gap:15px; justify-content:center; flex-wrap:wrap; margin-bottom:20px; padding:10px; border:1px dashed var(--gold-dark); background:rgba(255,255,255,0.3);">
                ${cleanKeys(money).map(k => `
                    <div style="display:flex; align-items:center; gap:5px;">
                        <i class="fa-solid fa-coins" style="color:var(--gold-dark)"></i>
                        <span style="font-size:0.9em;"><b>${money[k][0]}</b> ${k}</span>
                    </div>`).join('') || 'Không một xu dính túi'}
            </div>`;
            // 2. Bộ lọc
            const allItemKeys = cleanKeys(bags);
            // FIX: Đổi 'Loại' -> 'type'
            const types = ['Tất Cả', ...new Set(allItemKeys.map(k => SafeGet(bags[k], 'type[0]', 'Vật phẩm')))];
            const filterHtml = `<div style="margin-bottom:15px; display:flex; gap:5px; flex-wrap:wrap;">
                ${types.map(t => `<button class="magic-btn" onclick="window.UI.switchInvFilter('${t}')" style="${window.invFilter===t?'background:var(--gold-dark);color:#fff':''}">${t}</button>`).join('')}
            </div>`;
            // 3. Lọc & Phân trang
            // FIX: Đổi 'Loại' -> 'type'
            const filteredKeys = allItemKeys.filter(k => window.invFilter === 'Tất Cả' || !window.invFilter || SafeGet(bags[k], 'type[0]', 'Vật phẩm') === window.invFilter);
            const totalPages = Math.ceil(filteredKeys.length / ITEMS_PER_PAGE) || 1;

            if (pageState.bag > totalPages) pageState.bag = totalPages;
            const startIdx = (pageState.bag - 1) * ITEMS_PER_PAGE;
            const pagedKeys = filteredKeys.slice(startIdx, startIdx + ITEMS_PER_PAGE);
            // 4. Render Item
            const listHtml = pagedKeys.map(k => {
                const item = bags[k];
                const name = SafeGet(item, 'Tên[0]', k);
                const count = SafeGet(item, 'SốLượng[0]', 1);
                const desc = SafeGet(item, 'MôTả[0]', 'Một vật phẩm bí ẩn.');
                // FIX: Đổi 'Loại' -> 'type', 'CóThểDùng' -> 'usable'
                const type = SafeGet(item, 'type[0]', 'Vật phẩm');
                const canUse = SafeGet(item, 'usable[0]', false); 

                return `
                <details class="art-card" style="margin-bottom:8px;">
                    <summary class="bag-summary">
                        <div style="display:flex; align-items:center; gap:10px;">
                            <i class="fa-solid fa-box" style="color:var(--ink-secondary); font-size:0.8em;"></i>
                            <span style="font-weight:bold;">${name}</span>
                            <span style="font-size:0.8em; opacity:0.6;">x${count}</span>
                        </div>
                        <div style="display:flex; align-items:center; gap:8px;">
                            <span class="tag-pill" style="margin:0; font-size:0.7em;">${type}</span>
                            <i class="fa-solid fa-chevron-down" style="font-size:0.7em; opacity:0.4;"></i>
                        </div>
                    </summary>
                    <div class="bag-item-details">
                        <div style="font-style:italic; color:var(--ink-secondary); margin-bottom:10px; line-height:1.4;">
                            "${desc}"
                        </div>
                        <div style="display:flex; justify-content:flex-end; gap:10px; border-top:1px solid rgba(0,0,0,0.05); padding-top:8px;">
                            ${canUse ? `<button class="magic-btn" onclick="window.UI.send('/send [Sử dụng] ${k} |/trigger')">Sử dụng</button>` : `<span style="font-size:0.8em; opacity:0.5; align-self:center;">Không thể dùng trực tiếp</span>`}
                            <button class="magic-btn" style="border-color:#aaa; color:#666;" onclick="window.UI.send('/send [Vứt bỏ] ${k} |/trigger')">Vứt bỏ</button>
                        </div>
                    </div>
                </details>`;
            }).join('');

            return `<h2 class="art-title">Hành Trang</h2>${moneyHtml}${filterHtml}${listHtml || '<div style="text-align:center;padding:20px;opacity:0.5;">Trống rỗng...</div>'}${renderPaginationHtml('bag', totalPages)}`;
        }

        // [Việt Hóa & Đồng Bộ] Render Nhiệm Vụ
        function renderQuests() {
            // [ĐỒNG BỘ BIẾN] DanhSáchNhiệmVụ
            let tasks = SafeGet(currentData, 'DanhSáchNhiệmVụ[0]', null);
            const taskKeys = cleanKeys(tasks);
            if (taskKeys.length === 0) {
                return `<h2 class="art-title">Bảng Ủy Thác</h2>
                <div style="text-align:center; padding:30px; opacity:0.6; font-family:var(--font-header);">
                    <i class="fa-solid fa-scroll" style="font-size:2em; margin-bottom:10px;"></i><br>
                    ( Hiện không có nhiệm vụ )
                </div>`;
            }

            // Map dịch
            const transMap = {
                'gold': 'Vàng', 'money': 'Tiền', 'coin': 'Xu',
                'exp': 'Kinh nghiệm', 'xp': 'EXP',
                'item': 'Vật phẩm', 'fp': 'Điểm Vận Mệnh',
                'rep': 'Uy danh', 'reputation': 'Uy danh'
            };
            const translate = (k) => transMap[k.toLowerCase()] || k;

            const listHtml = taskKeys.map(k => {
                const task = tasks[k];
                if (!task || typeof task !== 'object') return '';

                const title = SafeGet(task, 'TiêuĐề[0]', `Nhiệm vụ ${k}`);
                const publisher = SafeGet(task, 'NgườiGiao[0]', 'Ẩn danh');
                const target = SafeGet(task, 'MụcTiêuHiệnTại[0]', '...');
                const difficulty = SafeGet(task, 'ĐộKhó[0]', 'E');
                const penalty = SafeGet(task, 'TrừngPhạtThấtBại[0]', 'Không');

                // Phần thưởng
                let rewardHtml = '';
                let rewardObj = SafeGet(task, 'PhầnThưởng[0]', null);
                if (isObject(rewardObj)) {
                    ['TiềnTệ', 'ThuộcTính'].forEach(cat => {
                         const catObj = SafeGet(rewardObj, cat, {});
                         if(isObject(catObj)) {
                             cleanKeys(catObj).forEach(ck => {
                                 const val = SafeGet(catObj, ck+'[0]', 0);
                                 if(val > 0) rewardHtml += `<span class="reward-badge"><i class="fa-solid fa-coins"></i> ${translate(ck)} x${val}</span>`;
                             });
                         }
                    });
                    const exp = SafeGet(rewardObj, 'KinhNghiệm[0]', 0);
                    if(exp > 0) rewardHtml += `<span class="reward-badge"><i class="fa-solid fa-star"></i> EXP x${exp}</span>`;
                    const fp = SafeGet(rewardObj, 'ĐiểmVậnMệnh[0]', 0);
                    if(fp > 0) rewardHtml += `<span class="reward-badge" style="color:var(--accent-red); border-color:var(--accent-red);"><i class="fa-solid fa-heart"></i> FP x${fp}</span>`;
                }
                if(rewardHtml === '') rewardHtml = '<span style="opacity:0.6; font-size:0.9em;">(Chưa rõ phần thưởng)</span>';
                return `
                <details class="art-card">
                    <summary class="card-header-area">
                        <div style="display:flex; align-items:center; gap:10px;">
                            <i class="fa-solid fa-scroll" style="color:var(--gold-dark);"></i>
                            <span style="font-family:var(--font-header); font-weight:bold;">${title}</span>
                        </div>
                        <div style="display:flex; align-items:center; gap:10px;">
                            <span style="font-family:var(--font-header); color:var(--ink-secondary); font-size:0.9em;">Cấp: ${difficulty}</span>
                            <span class="fold-indicator"><i class="fa-solid fa-angle-down"></i></span>
                        </div>
                    </summary>

                    <div class="card-body-area">
                        <div style="display:grid; grid-template-columns: 80px 1fr; gap:10px; margin-bottom:10px;">
                            <div style="text-align:right; color:var(--ink-secondary); font-weight:bold;">Người ủy thác:</div>
                            <div>${publisher}</div>

                            <div style="text-align:right; color:var(--ink-secondary); font-weight:bold;">Mục tiêu:</div>
                            <div style="color:var(--ink-primary); font-weight:bold;">${target}</div>
                        </div>

                        <div style="background:rgba(0,0,0,0.02); padding:8px; border-radius:4px; margin-top:10px;">
                            <div style="font-size:0.85em; color:var(--gold-dark); font-weight:bold; margin-bottom:4px;">
                                <i class="fa-solid fa-gift"></i> Thù Lao
                            </div>
                            <div style="display:flex; flex-wrap:wrap; gap:5px;">${rewardHtml}</div>
                        </div>

                        <div style="margin-top:8px; font-size:0.85em; color:var(--accent-red);">
                            <i class="fa-solid fa-triangle-exclamation"></i> Thất bại: ${penalty}
                        </div>
                    </div>
                </details>`;
            }).join('');

            return `<h2 class="art-title">Bảng Ủy Thác</h2>${listHtml}`;
        }

        // [Việt Hóa & Đồng Bộ] Render Từ Điển
        function renderCodex() {
            // [FIXED] Sửa 'TuDienTheGioi' thành 'TừĐiểnThếGiới' để khớp với biến.htm
            const list = SafeGet(currentData, 'TừĐiểnThếGiới[0]', {});
            const keys = cleanKeys(list);

            // --- Phân trang ---
            const totalPages = Math.ceil(keys.length / ITEMS_PER_PAGE);
            if (pageState.codex > totalPages) pageState.codex = totalPages || 1;
            const startIdx = (pageState.codex - 1) * ITEMS_PER_PAGE;

            const pagedKeys = keys.slice(startIdx, startIdx + ITEMS_PER_PAGE);
            // ----------------

            if (keys.length === 0) {
                return `<h2 class="art-title">Thư Viện Vạn Tượng</h2>
                <div style="text-align:center; padding:50px; opacity:0.5; font-family:var(--font-header);">
                    <i class="fa-solid fa-book-open" style="font-size:3em; margin-bottom:10px;"></i><br>
                    ( Chưa có dữ liệu )
                </div>`;
            }

            const listHtml = pagedKeys.map(k => {
                const title = SafeGet(list[k], 'TiêuĐề[0]', k);
                const type = SafeGet(list[k], 'PhânLoại[0]', 'Chung');
                const desc = SafeGet(list[k], 'MôTả[0]', '...').replace(/\\n/g, '<br>');

                return `
                <details class="codex-entry">
                    <summary class="codex-summary">
                        <span>${title}</span>
                        <span class="codex-tag">${type}</span>
                    </summary>
                    <div class="codex-content card-body-area">
                        <div class="codex-dropcap">${desc}</div>
                        <div style="text-align:right; margin-top:10px; opacity:0.4;">
                            <i class="fa-solid fa-feather-pointed"></i>
                        </div>
                    </div>
                </details>`;
