            return `
                <h2 class="art-title">Thư Viện Vạn Tượng</h2>
                <div style="padding:0 10px;" class="fade-effect">
                    ${listHtml}
                </div>
                ${renderPaginationHtml('codex', totalPages)}
            `;
        }

        // [Việt Hóa & Đồng Bộ] Render Tin Tức
        function renderNews() {
            // [ĐỒNG BỘ BIẾN] TinTứcHômNay
            const news = SafeGet(currentData, 'TinTứcHômNay', {});
            const keys = cleanKeys(news);
            const date = SafeGet(currentData, 'ThếGiới.ThờiGian[0]', 'Hôm Nay');
            if (keys.length === 0) {
                return `<h2 class="art-title">Lời Đồn Đại</h2><div style="text-align:center; padding:20px; opacity:0.6;">Hôm nay sóng yên biển lặng.</div>`;
            }

            const newsItems = keys.map((k, index) => {
                const content = SafeGet(news, k+'[0]', '...').replace(/\\n/g, '<br>');
                const isLast = index === keys.length - 1;

                return `
                <div class="news-article" style="margin-bottom:20px;">
                    <div class="news-header-line">
                        <div class="news-title">${k}</div>
                    </div>

                    <div class="news-meta">
                        <span>${date} • Bản Tin Đế Quốc</span>
                    </div>
                    <div class="news-body">
                        ${content}
                    </div>
                    ${!isLast ? `
                        <div class="news-divider"></div>
                        <div class="news-divider-icon">✦</div>
                    ` : ''}
                </div>`;
            }).join('');
            return `
            <h2 class="art-title">Lời Đồn Đại</h2>
            <div class="news-sheet">
                ${newsItems}
                <div style="margin-top:30px; text-align:center; font-size:0.8em; opacity:0.5; border-top:1px solid #ccc; padding-top:10px;">
                    — Thông tin chỉ mang tính tham khảo, cẩn thận tin đồn thất thiệt —
                </div>
            </div>`;
        }

        // --- [ 5. Hệ Thống Chiến Đấu ] ---
        window.Battle = {
            render: () => {
                // [ĐỒNG BỘ BIẾN] TrạngTháiChiếnĐấu
                const battleData = SafeGet(currentData, 'TrạngTháiChiếnĐấu[0]', {});
                // Giữ nguyên keys enemies/allies vì InitVar dùng tiếng Anh cho key này
                const allies = SafeGet(battleData, 'allies', {});
                const enemies = SafeGet(battleData, 'enemies', {});
                const allyKeys = cleanKeys(allies);
                const enemyKeys = cleanKeys(enemies);
                if (!battleTarget && (allyKeys.length || enemyKeys.length)) battleTarget = allyKeys[0] || enemyKeys[0];
                const renderUnit = (key, unit, isEnemy) => {
                    // FIX: Đổi key SinhMệnh -> HPHiệnTại, NăngLượng -> MPHiệnTại để khớp với JSON
                    const hp = SafeGet(unit, 'HPHiệnTại[0]', 0);
                    const maxHp = SafeGet(unit, 'HPTốiĐa[0]', 100);
                    const mp = SafeGet(unit, 'MPHiệnTại[0]', 0); const maxMp = SafeGet(unit, 'MPTốiĐa[0]', 100);
                    const selected = battleTarget === key ? 'selected' : '';
                    return `<div class="combatant ${selected}" onclick="window.Battle.select('${key}')"><div class="c-name"><span>${SafeGet(unit, 'Tên[0]', key)}</span> <small>${hp}/${maxHp}</small></div><div class="stat-mini-bar"><div class="hp-fill" style="width:${(hp/maxHp)*100}%"></div></div><div class="stat-mini-bar" style="height:3px; margin-top:2px;"><div class="mp-fill" style="width:${(mp/maxMp)*100}%"></div></div></div>`;
                };
                document.getElementById('ally-list').innerHTML = allyKeys.map(k => renderUnit(k, allies[k], false)).join('');
                document.getElementById('enemy-list').innerHTML = enemyKeys.map(k => renderUnit(k, enemies[k], true)).join('');
                window.Battle.renderPanel();
                const logs = SafeGet(battleData, 'combat_log', []);
                const logEl = document.getElementById('battle-log');
                logEl.innerHTML = (Array.isArray(logs) ? logs : [logs]).map(l => `<div class="log-entry">${l}</div>`).join('');
                logEl.scrollTop = logEl.scrollHeight;
                if(enemyKeys.length === 0 && allyKeys.length > 0) document.getElementById('end-battle-btn').classList.remove('hidden');
                else document.getElementById('end-battle-btn').classList.add('hidden');
            },
            select: (key) => { battleTarget = key; window.Battle.render(); },
            switchTab: (tab) => {
                battleTab = tab;
                document.getElementById('btn-b-skill').classList.toggle('active', tab==='skills');
                document.getElementById('btn-b-item').classList.toggle('active', tab==='items');
                window.Battle.renderPanel();
            },
            renderPanel: () => {
                const listEl = document.getElementById('battle-actions-list');
                listEl.innerHTML = '';
                if (!battleTarget) return;

                // Kiểm tra xem target có phải người chơi (Tên = <user> hoặc khớp tên NV Chính)
                const playerName = SafeGet(currentData, 'NhânVậtChính.Tên[0]', '<user>');
                // Logic đơn giản: Nếu target thuộc allies và là player

                if (battleTarget === 'player' || battleTarget === playerName || SafeGet(currentData, `TrạngTháiChiếnĐấu[0].allies.${battleTarget}`)) {
                    if (battleTab === 'skills') {
                        const skills = SafeGet(currentData, 'NhânVậtChính.KỹNăng[0]', {});
                        // FIX: Đổi 'TiêuHao' -> 'cost'
                        listEl.innerHTML = cleanKeys(skills).map(k => `<div class="action-row" onclick="window.Battle.sendAction('Sử dụng kỹ năng ${k}')"><span>${SafeGet(skills[k], 'Tên[0]', k)}</span> <small>${SafeGet(skills[k], 'cost[0]', '')}</small></div>`).join('') || 'Chưa học kỹ năng';
                    } else {
                        const items = SafeGet(currentData, 'TàiSản.BaLô[0]', {});
                        listEl.innerHTML = cleanKeys(items).map(k => `<div class="action-row" onclick="window.Battle.sendAction('Sử dụng vật phẩm ${k}')"><span>${SafeGet(items[k], 'Tên[0]', k)}</span> <small>x${SafeGet(items[k], 'SốLượng[0]', 1)}</small></div>`).join('') || 'Túi rỗng';
                    }
                } else { listEl.innerHTML = 'Không thể điều khiển đơn vị này'; }
            },
            sendAction: (act) => {
                const input = document.getElementById('battle-input');
                const name = battleTarget ? (SafeGet(currentData, `TrạngTháiChiếnĐấu[0].allies.${battleTarget}.Tên[0]`) || battleTarget) : 'Tôi';
                input.value = input.value ? input.value + '\n' + `${name} [${act}]` : `${name} [${act}]`;
            },
            submitInput: () => {
                const input = document.getElementById('battle-input');
                if(!input.value.trim()) return;
                window.UI.send(`/send ${input.value.replace(/\n/g, ' ')} |/trigger`);
                input.value = '';
            }
        };

        // --- [ 6. Khởi Động (Đồng Bộ Hóa) ] ---
        async function Init() {
            console.log("Đang tải dữ liệu Hư Không UI...");
            let data = {};
            try {
                // Lấy danh sách tin nhắn
                const hasChat = typeof getChatMessages === 'function';
                if (hasChat) {
                    const msgId = typeof getCurrentMessageId === 'function' ? getCurrentMessageId() : undefined;
                    const msgs = await getChatMessages(msgId) || [];

                    // [FIX 1] Quét từ dưới lên (tin nhắn mới nhất) để lấy stat_data
                    for (let i = msgs.length - 1; i >= 0; i--) {
                        if (msgs[i]?.data?.stat_data) {
                            data = msgs[i].data.stat_data;
                            break;
                        } else if (msgs[i]?.stat_data) {
                            data = msgs[i].stat_data;
                            break;
                        }
                    }
                }
            } catch(e) { console.log('Không lấy được dữ liệu ban đầu', e); }

            // [FIX 2] Gộp dữ liệu an toàn, không làm mất cấu trúc mặc định
            currentData = deepMerge({
                'TrạngTháiUI': {'GiaoDiệnHiệnTại': ['ThườngNgày']}, 
                'ThếGiới': {'ThờiGian':['--:--']}, 
                'NhânVậtChính': {'TàiNguyên':{'SinhMệnh':[100]}}
            }, data);

            renderAll();
        }

        // Tương thích môi trường SillyTavern / Web
        if (typeof waitGlobalInitialized === 'function') {
            waitGlobalInitialized('Mvu').then(() => {
                Init(); // Lần đầu load

                // [FIX 3] Bắt sự kiện riêng của MVU thông minh hơn
                if(typeof eventOn === 'function' && typeof Mvu !== 'undefined' && Mvu.events) {
                    eventOn(Mvu.events.VARIABLE_UPDATE_ENDED, payload => { 
                        // Dò tìm data ở các cấp độ JSON khác nhau
                        let newData = payload?.stat_data || payload?.data?.stat_data;
                        if (!newData && isObject(payload) && !payload.stat_data) newData = payload;

                        if (newData && isObject(newData)) { 
                            // Phải gộp (merge) thay vì gán đè (overwrite)
                            currentData = deepMerge(currentData, newData); 
                            renderAll(); 
                        } 
                    });
                }

                // [FIX 4] Lưới an toàn: Ép UI tự reload mỗi khi SillyTavern nhận tin nhắn mới
                if (typeof eventSource !== 'undefined') {
                    eventSource.on('MessageReceived', () => setTimeout(Init, 800));
                    eventSource.on('MessageUpdate', () => setTimeout(Init, 800));
                    eventSource.on('ChatLoaded', () => setTimeout(Init, 500));
                }
            });
        } else { 
            // Chế độ test trình duyệt
            setTimeout(Init, 100);
        }
    })();
