    const AudioSys = {
        muted: localStorage.getItem('lilith_muted') === 'true',
        toggleMute() {
            this.muted = !this.muted;
            localStorage.setItem('lilith_muted', this.muted);
            window.speechSynthesis.cancel();
            return this.muted;
        },
        getVoice(targetName) {
            const voices = window.speechSynthesis.getVoices();

            // LỌC NGHIÊM NGẶT: Quét toàn bộ máy, chỉ giữ lại các giọng có mã ngôn ngữ 'zh' (Tiếng Trung)
            let zhVoices = voices.filter(v => v.lang.includes('zh'));

            if (zhVoices.length === 0) return null; // Nếu trình duyệt chưa tải xong, tạm ngưng để tránh đọc sai ngôn ngữ

            // 1. Tìm đúng tên giọng (Xiaoxiao, Xiaoyi, Xiaomo...)
            let voice = zhVoices.find(v => v.name.includes(targetName));

            // 2. Nếu máy không cài giọng yêu cầu, ưu tiên tìm giọng Edge Online (chất lượng cao) của tiếng Trung
            if (!voice) voice = zhVoices.find(v => v.name.includes("Online") || v.name.includes("Neural"));

            // 3. Fallback cuối cùng: Bốc giọng Tiếng Trung đầu tiên có trong máy
            if (!voice) voice = zhVoices[0];

            return voice;
        },
        speak(text) {
            if (this.muted || !text) return;
            const cleanText = text.replace(/\[.*?\]/g, '').replace(/\(.*?\)/g, '').replace(/（.*?）/g, '').trim();
            if (!cleanText) return;

            window.speechSynthesis.cancel();
            const u = new SpeechSynthesisUtterance(cleanText);

            // Ép buộc cờ ngôn ngữ là Trung Quốc đại lục
            u.lang = 'zh-CN'; 

            const currentPersonaKey = userState.activePersona || 'xishi';
            const dbConfig = PERSONA_DB[currentPersonaKey].voice;
            const userConfig = userState.ttsConfig;

            const targetBase = dbConfig.base || 'Xiaoxiao'; 

            // Lấy giọng an toàn
            const selectedVoice = this.getVoice(targetBase);
            if (selectedVoice) {
                u.voice = selectedVoice;
            }

            u.pitch = userConfig.pitch || 1.0;
            u.rate = userConfig.rate || 1.0;

            window.speechSynthesis.speak(u);
        }
    };

