        },

        async checkAndSummarize(parentWin, force = false) {
            if (!force && panelChatHistory.length < MAX_HISTORY_TRIGGER) return;
            if (panelChatHistory.length <= HISTORY_KEEP && !force) return;
            this.showBubble(parentWin, "Đang ghi chép lại sử thi...", "#bd00ff");
            const toSummarize = panelChatHistory.slice(0, Math.max(0, panelChatHistory.length - HISTORY_KEEP));
            const keepHistory = panelChatHistory.slice(Math.max(0, panelChatHistory.length - HISTORY_KEEP));
            if (toSummarize.length === 0) {
                this.showBubble(parentWin, "Không có gì để tổng kết.", "#f00");
                return;
            }
            const textBlock = toSummarize.map(m => `${m.role}: ${m.content}`).join('\n');
            const prompt = `
            [System Task: Memory Consolidation]
            Summarize the following conversation in Vietnamese (Tiếng Việt).
            Focus on: Key events, User's fetishes revealed, Relationship changes, and Character's current mood cause.
            Keep it concise (under 200 words).
            Conversation:
            ${textBlock}
            `;
            try {
                const summary = await this.callUniversalAPI(parentWin, prompt, { 
                    isChat: false, 
                    mode: 'memory_internal', 
                    systemPrompt: "You are a historical archivist."
                });
                if (summary) {
                    userState.memoryArchive.push(summary.trim());
                    panelChatHistory = keepHistory;
                    saveChat();
                    saveState();
                    this.renderMemoryUI(parentWin);
                    this.showBubble(parentWin, "Ký ức đã được lưu.", "#0f0");
                } else {
                     this.showBubble(parentWin, "Tổng kết ký ức thất bại", "#f00");
                }
            } catch (e) {
                console.error("Summary failed", e);
                this.showBubble(parentWin, "Lỗi trí nhớ: " + e.message, "#f00");
            }
        },

        triggerRandomEvent(parentWin) {
            if (Math.random() > 0.005) return;

            const events = [
                {
                    id: 'trivia_time',
                    weight: 30,
                    run: () => {
                        const answers = ['ta yêu nàng', 'thích', 'yêu', 'love', 'tình'];
                        const reward = 50;
                        const msg = "【Thử lòng quân vương】\nNói ngay là chàng yêu thiếp! (Trong 3s)";
                        this.showBubble(parentWin, msg, "#ff0055");
                        AudioSys.speak("Mau nói, chàng có yêu thiếp không?");

                        const checkInput = () => {
                            const inputEl = parentWin.document.querySelector('#chat_input, #send_textarea, textarea');
                            if(inputEl && answers.some(a => inputEl.value.toLowerCase().includes(a))) {
                                AudioSys.speak("Tạm tin chàng lần này.");
                                this.showBubble(parentWin, `Thưởng ${reward} FP`, "#0f0");
                                updateFavor(2);
                                userState.fatePoints += reward;
                                saveState();
                                this.updateFP(parentWin, userState.fatePoints);
                            }
                        };
                        setTimeout(checkInput, 4000);
                    }
                },
                {
                    id: 'lucky_money',
                    weight: 20,
                    run: () => {
                        const amt = Math.floor(Math.random() * 50) + 10;
                        userState.fatePoints += amt;
                        saveState();
                        this.updateFP(parentWin, userState.fatePoints);
                        this.showBubble(parentWin, `Nhặt được ${amt} FP hoàng kim.`, "#ffd700");
                        AudioSys.speak("Có lộc trời cho kìa, không mau chia cho thiếp?");
                    }
                },
                {
                    id: 'stare',
                    weight: 30,
                    run: () => {
                        const av = parentWin.document.getElementById(avatarId);
                        av.classList.add('lilith-jealous'); 
                        this.showBubble(parentWin, "Liếc mắt nhìn đưa tình.........");
                        setTimeout(() => av.classList.remove('lilith-jealous'), 3000);
                    }
                },
                {
                    id: 'ransomware',
                    weight: 2, 
                    run: () => {
                        if (parentWin.document.getElementById(overlayId)) return;
                        const overlay = parentWin.document.createElement('div');
                        overlay.id = overlayId;
                        overlay.className = 'ransom-overlay';
                        overlay.innerHTML = `
                            <div class="ransom-box">
                                <h2 style="color:red; margin:0;">🔒 SẮC GIỚI PHONG ẨN</h2>
                                <p>Hồn phách của ngươi đã bị giam giữ.</p>
                                <p>Muốn mở khóa? Nộp <strong>100 FP</strong> mua trâm cài cho mỹ nhân.</p>
                                <div style="margin-top:20px; display:flex; gap:10px;">
                                    <button id="btn-pay-ransom" style="flex:1; background:#0f0; border:none; padding:10px; cursor:pointer; font-weight:bold;">Nộp ngân lượng (100 FP)</button>
                                    <button id="btn-refuse-ransom" style="flex:1; background:#555; border:none; padding:10px; cursor:pointer; color:#ccc;">Khước từ (Hảo cảm -5)</button>
                                </div>
                            </div>
                        `;
                        parentWin.document.body.appendChild(overlay);
                        AudioSys.speak("Không đưa tiền cho bổn cung thì đừng hòng đi đâu.", 0.6);

                        parentWin.document.getElementById('btn-pay-ransom').onclick = () => {
                            if (userState.fatePoints >= 100) {
                                userState.fatePoints -= 100;
                                updateFavor(2);
                                this.updateFP(parentWin, userState.fatePoints);
                                AudioSys.speak("Đa tạ công tử~");
                                overlay.remove();
                            } else {
                                alert("Đồ nghèo kiết xác! Cút!");
                                overlay.remove();
                            }
                        };
                        parentWin.document.getElementById('btn-refuse-ransom').onclick = () => {
                            updateFavor(-5);
                            AudioSys.speak("Hừ, đồ hẹp hòi.");
                            overlay.remove();
                        };
                    }
                }
            ];

            const totalWeight = events.reduce((acc, e) => acc + e.weight, 0);
            let random = Math.random() * totalWeight;
            for (const event of events) {
                if (random < event.weight) {
                    event.run();
                    break;
                }
                random -= event.weight;
            }
        },

