                @keyframes card-shake { 0% { transform: translate(1px, 1px) rotate(0deg); } 50% { transform: translate(-1px, -1px) rotate(-1deg); } 100% { transform: translate(1px, 1px) rotate(0deg); } }

                .avatar-breathing { animation: breathing 3s infinite ease-in-out; }
                @keyframes breathing { 0% { transform: scale(1); box-shadow: 0 0 15px var(--l-main); } 50% { transform: scale(1.03); box-shadow: 0 0 25px var(--l-main); } 100% { transform: scale(1); box-shadow: 0 0 15px var(--l-main); } }
                .lilith-jealous { border-color: #ff0000 !important; box-shadow: 0 0 30px #ff0000 !important; filter: sepia(1) hue-rotate(-50deg) saturate(3) !important; }

                .screen-glitch-layer { position: fixed; top: 0; left: 0; width: 100vw; height: 100vh; pointer-events: none; z-index: 99998; background: transparent; opacity: 0; transition: opacity 0.5s; mix-blend-mode: hard-light; }
                .sanity-critical { animation: glitch-skew 0.3s cubic-bezier(0.25, 0.46, 0.45, 0.94) both infinite; background: rgba(255, 0, 0, 0.05); }
                .sanity-critical::before, .sanity-critical::after { content: ""; position: absolute; top: 0; left: 0; width: 100%; height: 100%; }
                .sanity-critical::before { background: rgba(255,0,0,0.2); animation: glitch-anim-1 2s infinite linear alternate-reverse; }
                .sanity-critical::after { background: rgba(0,255,255,0.2); animation: glitch-anim-2 2s infinite linear alternate-reverse; }
                @keyframes glitch-skew { 0% { transform: skew(0deg); } 20% { transform: skew(-2deg); } 40% { transform: skew(2deg); } 60% { transform: skew(-1deg); } 80% { transform: skew(1deg); } 100% { transform: skew(0deg); } }
                @keyframes glitch-anim-1 { 0% { clip-path: inset(20% 0 80% 0); transform: translate(-2px,0); } 20% { clip-path: inset(60% 0 10% 0); transform: translate(2px,0); } 40% { clip-path: inset(40% 0 50% 0); transform: translate(-2px,0); } 60% { clip-path: inset(80% 0 5% 0); transform: translate(2px,0); } 80% { clip-path: inset(10% 0 70% 0); transform: translate(-2px,0); } 100% { clip-path: inset(30% 0 50% 0); transform: translate(2px,0); } }
                @keyframes glitch-anim-2 { 0% { clip-path: inset(10% 0 60% 0); transform: translate(2px,0); } 20% { clip-path: inset(30% 0 20% 0); transform: translate(-2px,0); } 40% { clip-path: inset(70% 0 30% 0); transform: translate(2px,0); } 60% { clip-path: inset(20% 0 60% 0); transform: translate(-2px,0); } 80% { clip-path: inset(50% 0 20% 0); transform: translate(2px,0); } 100% { clip-path: inset(10% 0 80% 0); transform: translate(-2px,0); } }

                .ransom-overlay { position:fixed; top:0; left:0; width:100%; height:100%; background:rgba(0,0,0,0.95); z-index:2147483647; display:flex; justify-content:center; align-items:center; }
                .ransom-box { background:#111; border:2px solid red; padding:30px; color:#fff; font-family:monospace; width:400px; box-shadow:0 0 50px red; text-align:center; animation: shake 0.5s infinite; }
                @keyframes shake { 0% { transform: translate(1px, 1px) rotate(0deg); } 10% { transform: translate(-1px, -2px) rotate(-1deg); } 20% { transform: translate(-3px, 0px) rotate(1deg); } 30% { transform: translate(3px, 2px) rotate(0deg); } 40% { transform: translate(1px, -1px) rotate(1deg); } 50% { transform: translate(-1px, 2px) rotate(-1deg); } 60% { transform: translate(-3px, 1px) rotate(0deg); } 70% { transform: translate(3px, 1px) rotate(-1deg); } 80% { transform: translate(-1px, -1px) rotate(1deg); } 90% { transform: translate(1px, 2px) rotate(0deg); } 100% { transform: translate(1px, -2px) rotate(-1deg); } }

                .loading .dot { animation: blink 1.4s infinite both; font-size: 20px; color: var(--l-cyan); }
                .loading .dot:nth-child(2) { animation-delay: 0.2s; }
                .loading .dot:nth-child(3) { animation-delay: 0.4s; }
                @keyframes blink { 0% { opacity: 0.2; } 20% { opacity: 1; } 100% { opacity: 0.2; } }
            `;
            parentWin.document.head.appendChild(style);
        },
        updateTheme(parentWin) {
            const wrapper = parentWin.document.getElementById(containerId);
            if (!wrapper) return;

            wrapper.classList.remove('theme-xishi', 'theme-zhaojun', 'theme-diaochan', 'theme-yangguifei');

            const current = userState.activePersona || 'xishi';

            wrapper.classList.add(`theme-${current}`);

            const input = parentWin.document.getElementById('lilith-chat-input');
            if (input && PERSONA_DB[current]) {
                const name = PERSONA_DB[current].name.split(' ')[1] || 'Mỹ Nhân';
                input.placeholder = `Trò chuyện cùng ${name}...`;
            }
        },
    };
    let attempts = 0;
    const loop = setInterval(() => {
        attempts++; const pWin = window.parent || window;
        if (pWin.document) {
            clearInterval(loop);
            if (pWin.jQuery) pWin.jQuery(pWin.document).ready(() => init(pWin));
            else init(pWin);
        } else if (attempts > 50) clearInterval(loop);
    }, 200);

    function init(pWin) {
        assistantManager.cssManage(pWin);
        assistantManager.initStruct(pWin);
        updateUI();
    }

 function updateUI() {
        const pWin = window.parent || window;
        const doc = pWin.document;
        const elVal = doc.getElementById('favor-val');
        const elSan = doc.getElementById('sanity-val');
        if(elVal) elVal.textContent = userState.favorability + '%';
        if(elSan) elSan.textContent = userState.sanity + '%';

        assistantManager.setAvatar(pWin);
        assistantManager.updateTheme(pWin); 
    }
})();

entries.content:
---
Quy tắc cập nhật biến (BẮT BUỘC dùng JSON Patch với op: replace/add/remove):
  TrạngTháiUI:
    GiaoDiệnHiệnTại:
      type: ["ThườngNgày" | "ChiếnĐấu", string]
      check:
        - Dùng lệnh "replace" đổi thành "ChiếnĐấu" khi có chiến đấu bạo lực trực diện xảy ra. Khi xung đột kết thúc, "replace" về lại "ThườngNgày".
  TrạngTháiChiếnĐấu[0]:
    in_combat:
      type: [boolean, string]
      check:
        - "replace" thành true/false đồng bộ với GiaoDiệnHiệnTại.
    enemies:
      type: |-
        {
          [enemy_key: string]: {
            Tên: [string, string];
            HPHiệnTại: [number, string];
            HPTốiĐa: [number, string];
            MPHiệnTại: [number, string];
            MPTốiĐa: [number, string];
          }
        }
      check:
        - "add" kẻ địch mới vào path: "/TrạngTháiChiếnĐấu/0/enemies/tên_kẻ_địch".
        - "replace" HP/MP tại path: "/TrạngTháiChiếnĐấu/0/enemies/tên_kẻ_địch/HPHiệnTại/0" (AI tự tính toán trừ máu sau mỗi đòn).
        - "remove" kẻ địch khi HP về 0 tại path "/TrạngTháiChiếnĐấu/0/enemies/tên_kẻ_địch".
    allies:
      type: |-
        {
          [ally_key: string]: {
            Tên: [string, string];
            HPHiệnTại: [number, string];
            HPTốiĐa: [number, string];
            MPHiệnTại: [number, string];
            MPTốiĐa: [number, string];
          }
        }
      check:
        - Dùng "add", "replace", "remove" tương tự như enemies khi có NPC hỗ trợ.
    combat_log:
      type: [string, string][]
      check:
        - Dùng "add" tại path "/TrạngTháiChiếnĐấu/0/combat_log/-" để đẩy dòng log chiến đấu mô tả hành động mới nhất vào cuối mảng.
  NhânVậtChính:
    TàiNguyên:
      type: |-
        {
          SinhMệnh: [number, string]; SinhMệnhTốiĐa: [number, string];
          NăngLượng: [number, string]; NăngLượngTốiĐa: [number, string];
          ThểLực: [number, string]; ThểLựcTốiĐa: [number, string]
        }
      check:
        - "replace" cập nhật chỉ số tại index 0 (Ví dụ: path "/NhânVậtChính/TàiNguyên/SinhMệnh/0"). Tuyệt đối không để rớt xuống dưới 0.
    TrangBị[0]:
      check:
        - "replace" cập nhật tên và mô tả ô tương ứng. Nếu tháo ra hoặc hỏng, "replace" thành "(Không)".
    HiệuỨngTrạngThái[0]:
      type: |-
        {
          [effect_key: string]: {
            Tên: [string, string]; MôTả: [string, string]; ThờiGianCònLại: [string, string];
          }
        }
      check:
        - "add" vào path "/NhânVậtChính/HiệuỨngTrạngThái/0/effect_key" khi dính buff/debuff. "remove" khi hết hạn.
    KỹNăng[0]:
      type: |-
        {
          [skill_key: string]: {
            Tên: [string, string]; CấpĐộ: [number, string]; cost: [string, string]; MôTả: [string, string]; tags: [string[], string];
          }
        }
      check:
        - "add" kỹ năng mới khi học được. "replace" CấpĐộ hoặc cost khi có thay đổi.
    ThốngKêTìnhDục[0]:
      check:
        - Khi mất zin, "replace" đường dẫn "/NhânVậtChính/ThốngKêTìnhDục/0/LàTraiTân/0" thành false.
        - "replace" tại "/NhânVậtChính/ThốngKêTìnhDục/0/SốLầnGiaoHợp/0" (AI tự nhẩm cộng 1 vào giá trị cũ).
  ThếGiới:
    ThờiGian, ĐịaĐiểm, ĐịaĐiểmLânCận, ThờiTiết, DanhTiếngHiệnTại, ÁpLựcThếGiới[0]:
      check:
        - Dùng "replace" tại index /0 của từng biến để đồng bộ liên tục bối cảnh và thời gian hiện tại.
  MốiQuanHệ[0]:
    type: |-
      {
        [npc_key: string]: {
          Tên: [string, string]; Tuổi: [number|string, string]; CấpĐộChiếnLực: [string, string]; CấpĐộ: [number, string];
          ChủngTộc: [string, string]; ThânPhận: [string, string]; NghềNghiệp: [string, string]; TínhCách: [string, string];
          SuyNghĩNộiTâm: [string, string]; SởThích: [string, string]; NgoạiHình: [string, string]; TrangPhục: [string, string];
          TrangBị: [string, string]; ĐánhGiá: [string, string]; HảoCảm: [string, string]; VịTríHiệnTại: [string, string];
          Vú: [string, string]; Lồn: [string, string]; LỗĐít: [string, string]; ChânNgọc: [string, string];
          LàTrinhNữ: [boolean, string]; SốLầnGiaoHợp: [number, string]; KinhNghiệmTìnhDục: [string, string]; SởThíchKỳQuặc: [string[], string];
        }
      }
    check:
      - "add" tạo profile mới tại path "/MốiQuanHệ/0/npc_key" ngay khi gặp nhân vật có tên.
      - "replace" HảoCảm/0 theo định dạng chuỗi "Số/1000" (VD: "25/1000").
      - 【QUY TẮC MIÊU TẢ SINH LÝ TỐI CAO - BẮT BUỘC TUÂN THỦ】
        + NẾU NPC LÀ NAM: Tuyệt đối KHÔNG MIÊU TẢ. Các trường Vú, Lồn, LỗĐít, ChânNgọc bỏ trống hoàn toàn.
        + NẾU NPC LÀ NỮ: Khi khởi tạo profile HOẶC khi có tương tác tình dục/kích thích, BẮT BUỘC dùng lệnh "replace" điền nội dung cực kỳ trực bạch, thô tục và chi tiết vào các trường sau:
          * "Vú/0": Miêu tả kích cỡ (vừa tay, khổng lồ xệ xuống...), hình dáng bầu ngực, độ mềm mại. Cực tả núm vú (màu sắc hồng phấn hay thâm sạm, sưng tấy cứng ngắc hay rụt rè), quầng vú rộng hay hẹp. Nếu có sữa hoặc dính tinh dịch phải ghi rõ.
          * "Lồn/0": Miêu tả chi tiết mép lồn (mọng nước lộn ra ngoài hay khép chặt e ấp, màu sắc thâm đen hay hồng hào). Trạng thái cửa mình (ướt đẫm dâm thủy dính ngáp, khít khao hay lỏng lẻo vì bị làm nhiều lần). Miêu tả cả âm vật (hạt đậu sưng to nhạy cảm). Nếu còn màng trinh phải ghi rõ.
          * "LỗĐít/0": Tả cơ vòng hậu môn (màu sắc thâm hay nhạt, khép chặt tít hay hơi xốp mở hé vì từng bị sử dụng). Bề mặt nếp nhăn ra sao, có sạch sẽ hay đang dính chất lỏng.
          * "ChânNgọc/0": Tả vòm bàn chân, ngón chân thon dài, móng chân (có sơn màu không). Cảm giác mềm mại của lòng bàn chân, mùi hương đặc trưng (mồ hôi xen lẫn nước hoa), độ nhạy cảm khi bị vuốt ve/liếm láp.
  HệThốngVậnMệnh:
    ĐiểmVậnMệnh:
      type: [number, string]
      check:
        - "replace" tại path "/HệThốngVậnMệnh/ĐiểmVậnMệnh/0" (AI tự tính toán số điểm hiện tại cộng/trừ số thay đổi).
    ĐốiTượngTơHồng[0]:
      type: |-
        {
          [npc_key: string]: NpcProfile & {
            HànhLangKýỨc: { [memory_key: string]: { TiêuĐề: [string, string]; MôTả: [string, string]; } };
            LịchTrình: [string, string];
          }
        }
      check:
        - Khi kết nối tơ hồng: Bắt buộc dùng "add" NPC vào "/HệThốngVậnMệnh/ĐốiTượngTơHồng/0/npc_key", ĐỒNG THỜI "remove" NPC đó khỏi "/MốiQuanHệ/0/npc_key".
        - TUÂN THỦ 【QUY TẮC MIÊU TẢ SINH LÝ TỐI CAO】 giống y hệt phần MốiQuanHệ[0]. Phải liên tục "replace" thay đổi trạng thái của Vú, Lồn, LỗĐít sau mỗi lần quan hệ hoặc bị kích thích (Ví dụ: từ khít thành lỏng, từ khô ráo thành lầy lội dâm dịch).
        - "add" hồi ức vào HànhLangKýỨc khi trải qua sinh tử/đột phá rào cản.
  DanhSáchNhiệmVụ[0]:
    type: |-
      {
        [task_key: string]: {
          TiêuĐề: [string, string]; NgườiGiao: [string, string]; ĐộKhó: [number, string]; MụcTiêuHiệnTại: [string, string];
          PhầnThưởng: [any, string]; TrừngPhạtThấtBại: [string, string];
        }
      }
    check:
      - "add" nhiệm vụ mới vào path "/DanhSáchNhiệmVụ/0/task_key".
      - CHÚ Ý: Hệ thống Tứ Đại Mỹ Nhân sẽ liên tục dùng quyền hạn để ép Hoài Phong nhận các nhiệm vụ mờ ám, sỉ nhục hoặc đầy nguy hiểm. Bắt buộc phải tạo TrừngPhạtThấtBại cực kỳ tàn khốc (như liệt dương, thiến, hút khô sinh mệnh).
      - "replace" tại "/DanhSáchNhiệmVụ/0/task_key/MụcTiêuHiệnTại/0" khi cập nhật tiến độ.
      - Bắt buộc dùng "remove" path "/DanhSáchNhiệmVụ/0/task_key" khi hoàn thành hoặc thất bại.
  TàiSản:
    TiềnTệ:
      check:
        - "replace" tại "/TàiSản/TiềnTệ/Vàng/0" (hoặc Bạc/Xu Đồng) (AI tự tính số dư mới).
    BaLô[0]:
      type: |-
        {
          [item_key: string]: { Tên: [string, string]; SốLượng: [number, string]; type: [string, string]; usable: [boolean, string]; MôTả: [string, string]; }
        }
      check:
        - Vật phẩm mới hoàn toàn: "add" vào "/TàiSản/BaLô/0/item_key".
        - Vật phẩm đã có: "replace" tại SốLượng/0.
        - Dùng hết (Số lượng = 0): Bắt buộc "remove" item_key khỏi "/TàiSản/BaLô/0".
  TinTứcHômNay:
    check:
      - Luôn luôn tự động cập nhật bối cảnh Tam Quốc dựa trên tiến trình thế giới, ngay cả khi cốt truyện chính chưa nhắc đến. Dùng "replace" tại "/TinTứcHômNay/Tên_Chuyên_Mục/0".
      - "Tin Nhanh Lưu Dân": Ghi lại tin tức từ đáy xã hội, các quận/làng lân cận (Ví dụ: làng bên bị dịch tả chết sạch, quan viên địa phương thu thuế nặng, nạn đói bùng phát...).
      - "Bảng Tin Quán Rượu": Ghi lại đại cục thiên hạ, tình hình chư hầu cát cứ (Ví dụ: Tào Tháo xuất binh phạt Từ Châu, Đổng Trác bị ám sát, quân khăn vàng nổi loạn...).
      - "Thế Giới Diệu Kỳ": Chuyên săn lùng bát quái, bê bối giật gân, chuyện thâm cung bí sử (Ví dụ: Vợ Tào Tháo lén cắm sừng hắn, Lữ Bố thích trói buộc...).
      - "Tiệc Trà Chiều Tứ Đại Mỹ Nhân": Cột bình luận riêng của Hệ thống AI. Dùng để buông lời độc mồm đánh giá khả năng giường chiếu của Hoài Phong, hoặc soi mói, chê bai, định giá những nữ nhân mà Hoài Phong vừa chạm trán.
  TừĐiểnThếGiới[0]:
    type: |-
      {
        [lore_key: string]: { TiêuĐề: [string, string]; PhânLoại: [string, string]; MôTả: [string, string]; }
      }
    check:
      - "add" vào path "/TừĐiểnThếGiới/0/lore_key" khi phát hiện sự kiện lịch sử, chủng tộc lạ, truyền thuyết, hoặc vật phẩm bí ẩn mới.
